+    if (qjs.JS_IsUndefined(val1) and qjs.JS_IsUndefined(val2)) return 1;
+    if (qjs.JS_IsNull(val1) or qjs.JS_IsNull(val2)) return 0;
+    if (qjs.JS_IsUndefined(val1) or qjs.JS_IsUndefined(val2)) return 0;
